let html_templates = '';

$.when(loadCard()).then(function(res) {
    
    $('.main-content').html(res);

    $('#myModal').modal('show');
}, function() {

    toastr.error( Lang.get('page.message.fail') );
});

$.when(getTemplatesHtml()).then(function(res) {

    html_templates = res;

    $('#box-left').html(res);

}, function() {

    toastr.error( Lang.get('page.message.fail') );
});

