$('body').on('click', '.create-new-page', function(event) {

    event.preventDefault();

    $.ajax({
        url: route('client.create-page'),
        type: 'GET',
    })
    .done(function(res) {

        $('.page').addClass('d-none');

        $('.page-main').addClass('d-none').removeClass('page-main');

        $('.main-content').append(res);
    })
    .fail(function() {
        
        toastr.error( Lang.get('page.message.fail') );
    });
});

$('body').on('click', '.choose-template', function(event) {

    event.preventDefault();

    $.ajax({
        url: route('client.choose-template'),
        type: 'GET',
        data: {
            id: $(this).attr('data-id'),
        }
    })
    .done(function(res) {

        if ($('.main-content').children('.page-main').length > 0) {

            $('.main-content').children('.page-main').replaceWith(res);
        } else {

            $('.main-content').append(res);
        }
    })
    .fail(function() {

        toastr.error( Lang.get('page.message.fail') );
    });
});

$('body').on('click', '.save', function(event) {

    event.preventDefault();

    let data = new Array();

    $('.page').each(function(index) {

        let boxes = [];
        
        $(this).find('.element').each(function() {
            boxes.push({
                id: $(this).attr('data-id'),
                div_style: $(this).attr('style'),
                textarea_style: $(this).children('textarea').attr('style'),
                content: $(this).children('textarea').val(),
            });
        });

        data.push({
            id: $(this).attr('data-id'),
            background: $(this).find('.background').find('img').attr('src').split('/').slice(-1)[0],
            boxes: boxes,
        });
    });
        
    $.ajax({
        url: route('client.save-card'),
        type: 'put',
        data: {
            pages: data,
        },
    })
    .done(function(res) {
        toastr.success( Lang.get('base.success') );
    })
    .fail(function() {
        toastr.error( Lang.get('page.message.fail') );
    });
});

$('body').on('click', '.trans-prev', function(event) {

    event.preventDefault();

    let current_page = parseInt($(this).attr('data-current-page'));

    let next_page = current_page == 0 ? parseInt($('.page').length) - 1 : current_page - 1;

    $('.page').eq(current_page).addClass('d-none').removeClass('page-main');

    $('.page').eq(next_page).removeClass('d-none').addClass('page-main');

    $(this).attr('data-current-page', next_page);

    $('.trans-next').attr('data-current-page', next_page);
});

$('body').on('click', '.trans-next', function(event) {

    event.preventDefault();

    let current_page = parseInt($(this).attr('data-current-page'));

    let next_page = current_page == parseInt($('.page').length) - 1 ? 0 : current_page + 1;

    $('.page').eq(current_page).addClass('d-none').removeClass('page-main');

    $('.page').eq(next_page).removeClass('d-none').addClass('page-main');

    $(this).attr('data-current-page', next_page);

    $('.trans-prev').attr('data-current-page', next_page);
});

$('body').on('click', '.box', function(event) {

    event.preventDefault();

    $(this).not('.d-none').addClass('d-none').addClass('page-main');
});

$('#select-font').on('click', function(event) {

    $('#font-box').toggleClass('d-none');
});

$('#select-size').on('click', function(event) {

    $('#size-box').toggleClass('d-none');

    $('.size-value').select();
});

$('#select-file').on('click', function(event) {

    $('#file-box').toggleClass('d-none');
});

$('#select-color').on('click', function(event) {

    $('#color-box').toggleClass('d-none');
});

