$('body').on('click', '.element', function(event) {

    event.preventDefault();

    $('.element').removeClass('element-new').removeClass('element-choose');

    $(this).addClass('element-choose');
})

$('body').on('click', '.btn-add-text', function(event) {

    event.preventDefault();

    let size = $(this).attr('data-font-size');

    let height = $(this).attr('data-height');

    let text = $(this).html().trim();

    let min_height = $(this).data('min-height');

    $('.element').removeClass('element-new').removeClass('element-choose').removeClass('drag');

    let html = '<div data-id="" class="element element-new element-choose drag" style="position: absolute;left: 20%;top: 40%;">'
        + '<textarea class="content" style="font-size: ' + size + ';height: ' + height + '" data-min-height="' + min_height + '" spellcheck="false">' + text + '</textarea></div>';
    
    $('.size-value').val(parseFloat(size));
    
    $('.editor-box').removeClass('d-none');

    $('.page-main').find('.card-wedding').find('.contain-box').append(html);
});

$('body').on('click mouseenter', '.drag', function() {

    element = $(this);

    displacejs(element.get(0), {

        constrain: false,

        relativeTo: null,

        onMouseDown: function() {},

        onMouseMove: function() {
            element.find('.content').css('opacity', 0.5);
        },

        onMouseUp: function() {
            element.find('.content').css('opacity', 1);
        }
    });
});

$('body').on('input', '.content', function(event) {

    event.preventDefault();

    $(this).height($(this).data('min-height')).height($(this)[0].scrollHeight - 25);

    $(this).width(40).width($(this)[0].scrollWidth);
});

$('.div-content').on('click', function(event) {

    event.preventDefault();

    if (event.target.class === 'editor-box') {

        return;
    }

    $('.editor-box').addClass('d-none');

    $('.box').not('.d-none').addClass('d-none');
});

$('body').on('click', '.content', function(event) {

    event.preventDefault();

    $(this).closest('.element').removeClass('element-new');

    $('.editor-box').removeClass('d-none');
});

$('body').on('click', '.delete-element', function(event) {

    event.preventDefault();

    $('.element-choose').remove();

    $('.editor-box').addClass('d-none');
});

$('body').on('click', '.font-element', function(event) {

    event.preventDefault();

    $('#font-box').toggleClass('d-none');

    let font = $(this).find('.font-value').html();

    $('.font-text').html(font);

    $('.element-choose').find('.content').css('font-family', font);

    $('.element-choose').find('.content').width($('.element-choose').find('.content').textWidth());
});

$('body').on('click', '.color-element', function(event) {

    event.preventDefault();

    let color = $(this).attr('data-color');

    $('.element-choose').find('.content').css('color', color);
});

$('body').on('click', '.size-element', function(event) {

    event.preventDefault();

    $('#size-box').toggleClass('d-none');

    let size = $(this).data('size-value');

    $('.size-value').val(size);

    $('.element-choose').find('.content').css('font-size', size);

    $(this).height($(this).data('min-height')).height($(this)[0].scrollHeight - 25);

    $('.element-choose').find('.content').width($('.element-choose').find('.content').textWidth());
});

$('body').on('input', '.size-value', function(event) {

    event.preventDefault();

    let size = $(this).val();

    console.log(size)

    $('.element-choose').find('.content').css('font-size', size);

    $('.element-choose').find('.content').width($('.element-choose').find('.content').textWidth());
});

$('.name-card').on('focusout', function() {

    let name = $(this).val();

    if (name != '') {
        $.ajax({
            url: route('client.update-name-card'),
            type: 'PUT',
            data: {
                name: $(this).val(),
            },
        })
        .done(function(res) {

            $(document).attr("title", res);
        })
        .fail(function() {

            toastr.error( Lang.get('page.message.fail') );
        });
    }   
});

// Calculate width of text from DOM element or string.
$.fn.textWidth = function(text, font) {
    if (!$.fn.textWidth.fakeEl) $.fn.textWidth.fakeEl = $('<span>').hide().appendTo(document.body);
    $.fn.textWidth.fakeEl.text(text || this.val() || this.text()).css('font', font || this.css('font'));
    return $.fn.textWidth.fakeEl.width();
};

function getTemplatesHtml() {
    return $.ajax({
        url: route('client.get-templates'),
        type: 'GET',
    });
}

function loadCard() {
    return $.ajax({
        url: route('client.load-card'),
        type: 'GET',
    });
}
